# shared_schemas.py
# No runtime logic — pure type + data definitions.

# 1. Define enums (all extend str for zero-effort JSON serialisation)
class TransportMode(str, Enum): WALK, BUS, TRAIN, SUBWAY, TAXI, FERRY
class Currency(str, Enum): CNY, JPY, KRW, ... (12 currencies)
class Preference(str, Enum): COST, TIME, SCENIC
class ErrorCode(str, Enum): OK, INVALID_CITY, INVALID_DATE, NO_ROUTE, ...
class Status(str, Enum): SUCCESS, PARTIAL, FAILED
class UpdateReason(str, Enum): ADDED_STOP, REMOVED_STOP, MODE_CHANGED

# 2. Define dataclasses with to_dict / from_dict / to_json methods
@dataclass Segment: transport_mode, origin, destination, departure_time, arrival_time, cost, currency, duration_minutes, distance_km, route_name, carbon_kg, score
@dataclass Stop: city, lat, lng, arrival_date, departure_date, accommodation, notes
@dataclass Diff: added_segments, removed_segments, cost_delta, time_delta_minutes, reason
@dataclass TravelInput: origin_city, origin_lat, origin_lng, stops, start_date, end_date, budget, currency, preference, transport_modes
@dataclass TravelOutput: route, stops, summary, budget_expansion, diff, status, error_code, error_message

